/* HomeReelMatch Embed Widget — build with: npm run embed:build */
(function(){const STYLES=`:host{display:block;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif}.hrm-feed{display:flex;gap:12px;overflow-x:auto;padding:8px 0;scrollbar-width:thin}.hrm-card{flex:0 0 160px;cursor:pointer;border-radius:8px;overflow:hidden;background:#1a1a2e;text-decoration:none;color:inherit;display:block;transition:transform .2s}.hrm-card:hover{transform:scale(1.03)}.hrm-thumb{width:100%;aspect-ratio:9/16;object-fit:cover;background:#0d0d1a;display:block}.hrm-thumb-placeholder{width:100%;aspect-ratio:9/16;background:linear-gradient(135deg,#1a1a2e 0%,#0d0d1a 100%);display:flex;align-items:center;justify-content:center;color:#666;font-size:12px}.hrm-info{padding:8px}.hrm-title{font-size:11px;color:#e0e0e0;line-height:1.4;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden}.hrm-error{padding:16px;text-align:center;color:#888;font-size:13px}`;function init(){document.querySelectorAll("[data-homereelmatch]").forEach(el=>{const apiUrl=el.dataset.apiUrl||"";const count=el.dataset.count?parseInt(el.dataset.count):undefined;const tag=el.dataset.tag;const sr=el.attachShadow({mode:"open"});const style=document.createElement("style");style.textContent=STYLES;sr.appendChild(style);const url=new URL(`${apiUrl}/api/embed/videos`);if(count)url.searchParams.set("count",String(count));if(tag)url.searchParams.set("tag",tag);fetch(url.toString(),{headers:{"Content-Type":"application/json"}}).then(r=>r.ok?r.json():Promise.reject(r.status)).then(({data})=>{const feed=document.createElement("div");feed.className="hrm-feed";data.forEach(v=>{const a=document.createElement("a");a.className="hrm-card";a.setAttribute("data-video-id",v.id);a.href=`${apiUrl}/watch/${v.id}`;a.target="_blank";a.rel="noopener noreferrer";if(v.thumbnailUrl){const img=document.createElement("img");img.className="hrm-thumb";img.src=v.thumbnailUrl;img.alt=v.title;img.loading="lazy";a.appendChild(img);}else{const p=document.createElement("div");p.className="hrm-thumb-placeholder";p.textContent=v.platform;a.appendChild(p);}const info=document.createElement("div");info.className="hrm-info";const t=document.createElement("p");t.className="hrm-title";t.textContent=v.title;info.appendChild(t);a.appendChild(info);feed.appendChild(a);});sr.appendChild(feed);}).catch(()=>{const e=document.createElement("div");e.className="hrm-error";e.textContent="エラーが発生しました。";sr.appendChild(e);});})}if(document.readyState==="loading"){document.addEventListener("DOMContentLoaded",init);}else{init();}})();
